class Solution:
    def circularArrayLoop(self, nums: List[int]) -> bool:
        n = len(nums)
        def nexti(i): return (i + nums[i]) % n
        for i in range(n):
            if not nums[i]: continue
            slow = fast = i
            fwd = nums[i] > 0
            while True:
                slow = nexti(slow)
                fast = nexti(nexti(fast))
                if nums[slow]*nums[i]<=0 or nums[fast]*nums[i]<=0: break
                if slow == fast:
                    if slow == nexti(slow): break
                    return True
            j = i
            while nums[j]*nums[i]>0:
                nums[j]=0; j=nexti(j)
        return False

