class Solution {
public:
    bool circularArrayLoop(vector<int>& nums) {
        int n=nums.size();
        auto nxt=[&](int i){ return (i+nums[i]%n+n)%n; };
        for(int i=0;i<n;i++){
            if(!nums[i]) continue;
            int slow=i, fast=i; int sgn=nums[i]>0?1:-1;
            while(true){
                slow=nxt(slow); fast=nxt(nxt(fast));
                if(nums[slow]*sgn<=0||nums[fast]*sgn<=0) break;
                if(slow==fast){
                    if(slow==nxt(slow)) break;
                    return true;
                }
            }
            int j=i; while(nums[j]*sgn>0){ nums[j]=0; j=nxt(j); }
        }
        return false;
    }
};
